chrome.runtime.onMessage.addListener((e,o,t)=>{if(e.type==="FETCH_IMAGE_BASE64")return l(e.url).then(r=>{chrome.runtime.sendMessage({type:"IMAGE_BASE64_READY",base64:r,url:e.url}),t({ok:!0})}).catch(r=>{console.error("ImageToPrompt: failed to fetch image",r),chrome.runtime.sendMessage({type:"IMAGE_BASE64_READY",base64:null,url:e.url}),t({ok:!1})}),!0});async function l(e){try{const t=await(await fetch(e)).blob();return new Promise((r,s)=>{const n=new FileReader;n.onloadend=()=>{const a=n.result.split(",")[1];r(a)},n.onerror=s,n.readAsDataURL(t)})}catch{return null}}
